	private File getSrcModelsDirectory() {
		URI dirUri = null;
		File dir = null;
		try {
			dirUri = this.getClass().getResource(".").toURI();
			dir = new File(dirUri);
		} catch (URISyntaxException e) {
		}
		while (dir != null && dir.getParentFile() != null) {
			if (dir.getName().equalsIgnoreCase("bin")) {
				return new File(dir.getParentFile(), "src/Models");
			}
			dir = dir.getParentFile();
		}
		return null;
	}
	public void writeCountersData() {
		String dirPath = getSrcModelsDirectory().getAbsolutePath() + "/result";

		if(!new File(dirPath).exists()) {
		new File(dirPath).mkdir();
	}
	try{
		BufferedWriter writer = new BufferedWriter(new FileWriter(dirPath + "/Result.csv",true));
		writer.write(getName() + ";");
		writer.write("countCoordinateReceived = " + Integer.toString(countCoordinateReceived) + ";");
		countCoordinateReceived = 0;
		writer.write("countVisualPerceptionReceived = " + Integer.toString(countVisualPerceptionReceived) + ";");
		countVisualPerceptionReceived = 0;
		writer.write("countCaptureReceived = " + Integer.toString(countCaptureReceived) + ";");
		countCaptureReceived = 0;
		writer.write("countperceptionThreshold = " + Integer.toString(countperceptionThreshold) + ";");
		countperceptionThreshold = 0;
		writer.newLine();
		writer.close();
	}catch(Exception e) {}
	}
