	public void deletionOperator(AtomicModel toRemove) {
		connections.clear();
		for(Coupling e : getParent().getCouplings()) {
			if(!e.getSource().getName().contains("StimuliGenerator") && !e.getDestination().getName().contains("DRC"))
				connections.add(new Connection((AtomicModelImpl) e.getSource(), e.getSourcePort(), (AtomicModelImpl)e.getDestination(), e.getDestinationPort()));
		}	
		constituents = initializeConstituents();
		this.toRemove = (AtomicModelImpl) toRemove;
		removeConstituent((AtomicModelImpl) toRemove);
		if(toRemove instanceof Mediator4)
			transmitters.remove(toRemove);
		if(toRemove instanceof CrowdGateway1)
			crowdGateways.remove(toRemove);
		if(toRemove instanceof Mediator3)
			transmitters.remove(toRemove);
		if(toRemove instanceof Drone4)
			drones.remove(toRemove);
		if(toRemove instanceof Drone3)
			drones.remove(toRemove);
		if(toRemove instanceof Drone2)
			drones.remove(toRemove);
		if(toRemove instanceof Drone1)
			drones.remove(toRemove);
		if(toRemove instanceof CrowdMediator1)
			crowdTransmitters.remove(toRemove);
		if(toRemove instanceof CrowdMediator2)
			crowdTransmitters.remove(toRemove);
		if(toRemove instanceof Crowd1)
			crowds.remove(toRemove);
		if(toRemove instanceof Crowd2)
			crowds.remove(toRemove);
		if(toRemove instanceof Sensor4)
			sensors.remove(toRemove);
		if(toRemove instanceof DroneMediator1)
			droneTransmitters.remove(toRemove);
		if(toRemove instanceof DroneMediator2)
			droneTransmitters.remove(toRemove);
		if(toRemove instanceof Sensor2)
			sensors.remove(toRemove);
		if(toRemove instanceof DroneBasis1)
			droneBasiss.remove(toRemove);
		if(toRemove instanceof Sensor3)
			sensors.remove(toRemove);
		if(toRemove instanceof DroneBasis2)
			droneBasiss.remove(toRemove);
		if(toRemove instanceof Mediator2)
			transmitters.remove(toRemove);
		if(toRemove instanceof Sensor1)
			sensors.remove(toRemove);
		if(toRemove instanceof Mediator1)
			transmitters.remove(toRemove);
		if(toRemove instanceof Gateway)
			gateways.remove(toRemove);
		if(toRemove instanceof DroneMediator3)
			droneTransmitters.remove(toRemove);
		if(toRemove instanceof DroneMediator4)
			droneTransmitters.remove(toRemove);

		AtomicModel sg = null;
		for(AtomicModel e : getParent().getChildren()) {
			if(e.getName().equals("StimuliGenerator" + toRemove.getName())) {
				sg = e;
				break;
			}
		}
		if(sg != null) {
			getParent().removeChildModel(sg);
			mS4MESimulationInterface.finalizeConstituent((AtomicModelImpl) sg);
		}	
		syncModel();
	}
