<%
	private void syncModel() {
		try{
			ArrayList<Connection> aux = new ArrayList<Connection>();
			LinkedHashMap<String,String> map = aux3SyncModel();
			if(!new File("Model").exists()) {
				new File("Model").mkdir();
			}

			connections.clear();
			for(Coupling a : getParent().getCouplings()) {
				Connection e = new Connection((AtomicModelImpl)a.getSource(), a.getSourcePort(), (AtomicModelImpl)a.getDestination(), a.getDestinationPort());
				if ( !( e.inPort.getName().contains("Checked") || e.outClass.getName().contains("StimuliGenerator") || e.inPort.getName().contains("Remove"))) { 
					if(e != null && e.inClass != null && e.outClass != null && e.inPort != null && e.outPort != null) {
						connections.add(e);
					}
				} 
			}

			BufferedWriter writer = new BufferedWriter(new FileWriter(getModelsDirectory2().getAbsolutePath() + "/sosadl/"+ getName().replace("DRC","")+"REC"+Integer.toString(syncCount)+".sosadl"));

			writer.write(aux1SyncModel());
			writer.newLine();
			for(AtomicModel e : getParent().getChildren()) {
				if(!e.getName().contains("StimuliGenerator") && !e.getName().contains("DRC") && !e.getName().contains("ExOp") ) {
					writer.write("			" + e.getName() + " is " + getTypeCons((AtomicModelImpl)e));
					writer.newLine();
				}
			}

			writer.write("		}");
			writer.newLine();

			writer.write("		binding{");
			writer.newLine();
			writer.flush();
			for(Connection e : connections) {
				writer.write("			unify one{ " + e.outClass.getName()+((map.containsKey(getTypeCons(e.outClass).toUpperCase()+e.outPort.getName().replaceFirst("out","").toUpperCase()))?"::"+map.get(getTypeCons(e.outClass).toUpperCase()+e.outPort.getName().replaceFirst("out","").toUpperCase()):"")+"::"+e.outPort.getName().replaceFirst("out","") + "} to one {" + e.inClass.getName()+((map.containsKey(getTypeCons(e.inClass).toUpperCase()+e.inPort.getName().replaceFirst("in","").toUpperCase()))?"::"+map.get(getTypeCons(e.inClass).toUpperCase()+e.inPort.getName().replaceFirst("in","").toUpperCase()):"")+"::" + e.inPort.getName().replaceFirst("in","")+ "}" + ((connections.indexOf(e) != connections.size()-1)? " and": ""));
				writer.newLine();

			} 

			writer.write(aux2SyncModel());
			writer.newLine();

			connections.addAll(aux);
			writer.close();
			syncCount++;
		} catch (Exception e) {
			e.printStackTrace();
		}
	}

